// Parse comparison request
const inputData = $input.first()?.json || {};
const modelIds = inputData.model_ids || [];
const runIds = inputData.run_ids || [];
const categories = inputData.categories || ['performance', 'accuracy'];

return {
  json: {
    comparison_id: `cmp_${Date.now()}`,
    model_ids: modelIds,
    run_ids: runIds,
    categories: categories,
    comparison_type: modelIds.length > 0 ? 'model' : 'run',
    requested_at: new Date().toISOString(),
    requested_by: inputData.requested_by || 'api'
  }
};

// Process and compare metrics
const model1 = $node["Fetch Model 1"].json?.data || {};
const model2 = $node["Fetch Model 2"].json?.data || {};
const model3 = $node["Fetch Model 3"].json?.data || {};
const compareData = $node["Fetch Metrics Compare"].json?.data || {};
const aggregate1 = $node["Fetch Aggregate 1"].json?.data || [];
const aggregate2 = $node["Fetch Aggregate 2"].json?.data || [];

// Build comparison table
const models = [model1, model2, model3].filter(m => m.id);
const modelNames = models.map(m => m.name || m.checkpoint || 'Unknown');

// Compare key metrics
const metricsComparison = {};

// Helper to find metric by name
const findMetric = (aggregates, name) => aggregates.find(m => m.name === name);

// TTFT Comparison
const ttft1 = findMetric(aggregate1, 'seconds_to_first_token');
const ttft2 = findMetric(aggregate2, 'seconds_to_first_token');
if (ttft1 && ttft2) {
  const better = ttft1.mean < ttft2.mean ? modelNames[0] : modelNames[1];
  const diff = ((ttft1.mean - ttft2.mean) / ttft2.mean * 100).toFixed(1);
  metricsComparison['seconds_to_first_token'] = {
    [modelNames[0]]: { value: ttft1.mean.toFixed(3), unit: ttft1.unit },
    [modelNames[1]]: { value: ttft2.mean.toFixed(3), unit: ttft2.unit },
    better: better,
    diff_percent: Math.abs(diff)
  };
}

// TPS Comparison
const tps1 = findMetric(aggregate1, 'token_generation_tokens_per_second');
const tps2 = findMetric(aggregate2, 'token_generation_tokens_per_second');
if (tps1 && tps2) {
  const better = tps1.mean > tps2.mean ? modelNames[0] : modelNames[1];
  const diff = ((tps1.mean - tps2.mean) / tps2.mean * 100).toFixed(1);
  metricsComparison['token_generation_tokens_per_second'] = {
    [modelNames[0]]: { value: tps1.mean.toFixed(2), unit: tps1.unit },
    [modelNames[1]]: { value: tps2.mean.toFixed(2), unit: tps2.unit },
    better: better,
    diff_percent: Math.abs(diff)
  };
}

// Memory Comparison
const mem1 = findMetric(aggregate1, 'max_memory_used_gbyte');
const mem2 = findMetric(aggregate2, 'max_memory_used_gbyte');
if (mem1 && mem2) {
  const better = mem1.mean < mem2.mean ? modelNames[0] : modelNames[1];
  const diff = ((mem1.mean - mem2.mean) / mem2.mean * 100).toFixed(1);
  metricsComparison['max_memory_used_gbyte'] = {
    [modelNames[0]]: { value: mem1.mean.toFixed(2), unit: mem1.unit },
    [modelNames[1]]: { value: mem2.mean.toFixed(2), unit: mem2.unit },
    better: better,
    diff_percent: Math.abs(diff)
  };
}

// Overall winner calculation
let model1Wins = 0;
let model2Wins = 0;
Object.values(metricsComparison).forEach(m => {
  if (m.better === modelNames[0]) model1Wins++;
  else if (m.better === modelNames[1]) model2Wins++;
});

const overallWinner = model1Wins > model2Wins ? modelNames[0] : model2Wins > model1Wins ? modelNames[1] : 'Tie';

return {
  json: {
    comparison_id: $input.first().json.comparison_id,
    models: models.map(m => ({
      id: m.id,
      name: m.name,
      checkpoint: m.checkpoint,
      family: m.family,
      type: m.type,
      quantization: m.quantization
    })),
    metrics_comparison: metricsComparison,
    overall_winner: overallWinner,
    win_counts: {
      [modelNames[0]]: model1Wins,
      [modelNames[1]]: model2Wins
    },
    compared_at: new Date().toISOString()
  }
};

// Generate HTML comparison report
const data = $input.first().json;
const models = data.models;
const comparison = data.metrics_comparison;

const modelHeaders = models.map(m => `<th>${m.name || m.checkpoint}</th>`).join('');

// TTFT Row
const ttftData = comparison['seconds_to_first_token'];
const ttftRow = ttftData ? `
  <tr>
    <td>Seconds to First Token</td>
    ${models.map(m => {
      const val = ttftData[m.name];
      const isBetter = ttftData.better === m.name;
      return `<td style="${isBetter ? 'background: #d4edda; font-weight: bold;' : ''}">${val ? val.value + ' ' + val.unit : 'N/A'}</td>`;
    }).join('')}
    <td>${ttftData.diff_percent.toFixed(1)}%</td>
  </tr>` : '';

// TPS Row
const tpsData = comparison['token_generation_tokens_per_second'];
const tpsRow = tpsData ? `
  <tr>
    <td>Token Generation TPS</td>
    ${models.map(m => {
      const val = tpsData[m.name];
      const isBetter = tpsData.better === m.name;
      return `<td style="${isBetter ? 'background: #d4edda; font-weight: bold;' : ''}">${val ? val.value + ' ' + val.unit : 'N/A'}</td>`;
    }).join('')}
    <td>${tpsData.diff_percent.toFixed(1)}%</td>
  </tr>` : '';

// Memory Row
const memData = comparison['max_memory_used_gbyte'];
const memRow = memData ? `
  <tr>
    <td>Max Memory (GB)</td>
    ${models.map(m => {
      const val = memData[m.name];
      const isBetter = memData.better === m.name;
      return `<td style="${isBetter ? 'background: #d4edda; font-weight: bold;' : ''}">${val ? val.value + ' ' + val.unit : 'N/A'}</td>`;
    }).join('')}
    <td>${memData.diff_percent.toFixed(1)}%</td>
  </tr>` : '';

const html = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Segoe UI', Arial, sans-serif; margin: 20px; background: #f5f5f5; }
    .container { max-width: 1000px; margin: 0 auto; background: white; border-radius: 12px; overflow: hidden; box-shadow: 0 4px 6px rgba(0,0,0,0.1); }
    .header { background: linear-gradient(135deg, #28a745 0%, #20c997 100%); color: white; padding: 30px; text-align: center; }
    .content { padding: 30px; }
    .winner-banner { background: #fff3cd; border: 2px solid #ffc107; padding: 20px; border-radius: 8px; text-align: center; margin: 20px 0; }
    .winner-name { font-size: 24px; font-weight: bold; color: #856404; }
    table { width: 100%; border-collapse: collapse; margin: 20px 0; }
    th { background: #343a40; color: white; padding: 15px; text-align: left; }
    td { padding: 15px; border-bottom: 1px solid #dee2e6; }
    tr:hover { background: #f8f9fa; }
    .model-card { display: inline-block; background: #f8f9fa; padding: 20px; border-radius: 8px; margin: 10px; min-width: 200px; }
    .model-card h3 { margin: 0 0 10px; color: #495057; }
    .metric-row { display: flex; justify-content: space-between; padding: 5px 0; border-bottom: 1px solid #dee2e6; }
    .footer { background: #343a40; color: white; padding: 20px; text-align: center; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>🏆 Model Comparison Report</h1>
      <p>Generated: ${new Date(data.compared_at).toLocaleString()}</p>
    </div>

    <div class="content">
      <h2>Models Compared</h2>
      ${models.map(m => `
        <div class="model-card">
          <h3>${m.name || m.checkpoint}</h3>
          <div class="metric-row"><span>Family:</span><strong>${m.family || 'N/A'}</strong></div>
          <div class="metric-row"><span>Type:</span><strong>${m.type || 'N/A'}</strong></div>
          <div class="metric-row"><span>Quantization:</span><strong>${m.quantization || 'N/A'}</strong></div>
        </div>
      `).join('')}

      <div class="winner-banner">
        <p style="margin: 0; font-size: 18px;">Overall Winner</p>
        <p class="winner-name">🏆 ${data.overall_winner}</p>
        <p style="margin: 10px 0 0; color: #856404;">
          ${data.win_counts ? Object.entries(data.win_counts).map(([m, c]) => `${m}: ${c} metrics`).join(' | ') : ''}
        </p>
      </div>

      <h2>Performance Comparison</h2>
      <table>
        <thead>
          <tr>
            <th>Metric</th>
            ${models.map(m => `<th>${m.name || m.checkpoint}</th>`).join('')}
            <th>Difference</th>
          </tr>
        </thead>
        <tbody>
          ${ttftRow}
          ${tpsRow}
          ${memRow}
        </tbody>
      </table>

      <p style="background: #e7f3ff; padding: 15px; border-radius: 8px; border-left: 4px solid #007bff; margin-top: 20px;">
        <a href="${$env.DASHBOARD_FRONTEND_URL || 'http://localhost:3000'}/compare?comparison=${data.comparison_id}" style="color: #007bff; text-decoration: none; font-weight: bold;">View interactive comparison</a> with detailed charts and analysis.
      </p>
    </div>

    <div class="footer">
      <p>Lemonade Eval Dashboard | Model Comparison Tool</p>
    </div>
  </div>
</body>
</html>
`;

return { json: { html, text: `Model Comparison: ${data.overall_winner} wins` } };

